// 获取 body 对象
const body = $('Webhook').first().json.body;

// 1. 处理 machine_data_id
// 先获取原始值
let rawDataId = body.machine_data_id;
// 如果它是数组，就取第一个元素；如果是数字或字符串，保持原样
if (Array.isArray(rawDataId)) {
    rawDataId = rawDataId[0];
}
// 关键一步：用 String() 包裹，确保它是字符串，才能使用 .replace
const cleanMachine_data_id = String(rawDataId).replace(/\s/g, '');

// 2. 处理 retroid
const cleanRetroid = String(body.retroid).replace(/\s/g, '');

// 3. 处理 remark
const cleanRemark = String(body.remark).replace(/\s/g, '');

return {
  machine_data_id: cleanMachine_data_id,
  retroid: cleanRetroid,
  remark: cleanRemark
};

const input = $input.all()[0].json;
const machineDataId = input.body?.machine_data_id || input.query?.machine_data_id;

let isSingleId;
let finalId = machineDataId; // 增加一个变量用于后续使用方便（可选）

if (machineDataId === undefined) {
  // 情况 1：未传参
  isSingleId = true; 
} else if (Array.isArray(machineDataId)) {
  // 情况 2：是数组
  if (machineDataId.length > 1) {
      // 确实是多个 ID
      isSingleId = false;
  } else {
      // 虽然是数组，但只有一个 ID (例如 [2344790])，或者是空数组
      isSingleId = true;
      // 如果你后续作为单 ID 处理，可能需要把值取出来
      if(machineDataId.length === 1) {
          finalId = machineDataId[0];
      }
  }
} else {
  // 情况 3：单个 ID（字符串或数字）
  isSingleId = true;
}

return {
  json: {
    isSingleId,   // 现在如果是 [123]，这里会是 true
    machineDataId: finalId // 如果是单ID模式，你可以直接输出取出的值，方便后面用
  }
};

// 1. 取到指定节点的第一个item
const item = $('判断machine_data_id是否为真').first().json;

// 2. 获取实际对象（无论数组还是对象）
// 若是数组且length>0，取第0个
const first = Array.isArray(item) ? item[0] : item || {};

// 3. 统一处理data
const data = first.data || first; // 有data用data，无data直接用

let result = '';
if (data.Station) {
  result = data.Station + '解绑';
} else if (data.procedure_name) {
  // 保证有至少2个字，否则slice(0, -2)会报错
  const base = data.procedure_name || '';
  result = base.length > 2 ? base.slice(0, -2) + '解绑' : base + '解绑';
} else if (first.procedure_name) {
  const base = first.procedure_name || '';
  result = base.length > 2 ? base.slice(0, -2) + '解绑' : base + '解绑';
}
return { json: { result } };

